    ['m??ltiples','m&uacute;ltiples'], ['m??xima','m&aacute;xima'], ['r??pida','r&aacute;pida'], ['reposici??n','reposici&oacute;n'],
    ['est??ndar','est&aacute;ndar'], ['alg??n','alg&uacute;n'], ['??til','&uacute;til'], ['port??til','port&aacute;til']
  ];
  const subjectMap = htmlMap.map(([bad, good]) => [bad, good
    .replace(/&aacute;/g,'a').replace(/&eacute;/g,'e').replace(/&iacute;/g,'i').replace(/&oacute;/g,'o').replace(/&uacute;/g,'u')
    .replace(/&Aacute;/g,'A').replace(/&Eacute;/g,'E').replace(/&Iacute;/g,'I').replace(/&Oacute;/g,'O').replace(/&Uacute;/g,'U')
    .replace(/&uuml;/g,'u').replace(/&Uuml;/g,'U').replace(/&ntilde;/g,'n').replace(/&Ntilde;/g,'N')]);
  for (const [bad, good] of (forSubject ? subjectMap : htmlMap)) text = text.split(bad).join(good);
  text = text.split(' ?? ').join(forSubject ? ' - ' : ' &bull; ');
  text = text.split('??').join(forSubject ? '-' : '&bull;');
  return text;
}

function applyVisualFlags(html, data) {
  if (!html) return html;
  if (!flagEnabled(data, 'include_summary', true)) {
