const item = $input.first();
const body = item?.json?.body || {};
const errors = [];

function text(name) {
  return String(body[name] ?? '').trim();
}

function positiveNumber(name) {
  const raw = body[name];
  if (raw === undefined || raw === null || raw === '') return false;
  const n = Number(raw);
  return Number.isFinite(n) && n > 0;
}

function validDateText(name) {
  const value = text(name);
  if (!value) return false;
  const parsed = new Date(value.replace(' ', 'T'));
  return !Number.isNaN(parsed.getTime());
}

function dateWindowState() {
  const hasStart = text('start_date').length > 0;
  const hasEnd = text('end_date').length > 0;
  if (!hasStart && !hasEnd) return { provided: false, valid: false };
  if (!hasStart || !hasEnd) return { provided: true, valid: false, error: 'start_date y end_date deben enviarse juntos.' };
  if (!validDateText('start_date') || !validDateText('end_date')) return { provided: true, valid: false, error: 'start_date y end_date deben ser fechas v\u00e1lidas.' };
  const start = new Date(text('start_date').replace(' ', 'T'));
  const end = new Date(text('end_date').replace(' ', 'T'));
  if (start > end) return { provided: true, valid: false, error: 'start_date no puede ser mayor que end_date.' };
  return { provided: true, valid: true };
}

if (!text('email_to')) {
  errors.push('email_to es obligatorio para llamadas webhook.');
}

const webhookPath = 'cmdb-inventario-activos-contactos';
const window = dateWindowState();

if (webhookPath === 'cmdb-movimientos-recientes-inventario') {
  const hasMovementDays = positiveNumber('movement_days');
  if (!hasMovementDays && !window.valid) {
    errors.push(window.error || 'Debe enviar movement_days positivo o la ventana start_date + end_date.');
  }
}

if (webhookPath === 'cmdb-activos-proximos-vencer-garantia') {
  if (!positiveNumber('warranty_warning_months')) {
    errors.push('warranty_warning_months es obligatorio y debe ser un numero mayor a 0.');
  }
}

if (webhookPath === 'itsm-tickets-sin-actualizacion-24h') {
  if (!positiveNumber('stale_threshold_hours')) {
    errors.push('stale_threshold_hours es obligatorio y debe ser un numero mayor a 0.');
  }
}

if (window.provided && !window.valid && webhookPath !== 'cmdb-movimientos-recientes-inventario') {
  errors.push(window.error || 'Ventana de fechas inv\u00e1lida.');
}

const valid = errors.length === 0;

return [{
  json: {
    ...(item.json || {}),
    webhook_contract: {
      valid,
      status_code: valid ? 202 : 400,
      message: valid ? 'Workflow accepted' : errors.join(' '),
      errors,
    },
  },
  binary: item.binary,
}];

const item = $input.first();
const json = item?.json || {};

if (!json.webhook_contract?.valid) {
  return [];
}

const { webhook_contract, ...cleanJson } = json;
return [{ json: cleanJson, binary: item.binary }];
